Index lifecycle management
Track every chunk’s index state and handle re-indexing on document change:
import hashlib

def compute_hash(content: str) -&gt; str:
    return hashlib.sha256(content.encode()).hexdigest()

def mark_stale_on_update(document_id: str, new_chunks: list[dict]):
    """Mark existing chunks stale if content has changed."""
    existing = DocumentChunk.objects.filter(document_id=document_id)
    new_hashes = {c["chunk_index"]: compute_hash(c["content"]) for c in new_chunks}

    to_stale = [
        c.id for c in existing
        if new_hashes.get(c.chunk_index) != c.content_hash
    ]

    DocumentChunk.objects.filter(id__in=to_stale).update(index_status="stale")

def reindex_stale(batch_size: int = 100):
    """Celery task — pick up stale chunks and re-embed."""
    stale = DocumentChunk.objects.filter(index_status="stale")[:batch_size]
    if not stale:
        return

    texts = [c.content for c in stale]
    embeddings = embed(texts)

    for chunk, vec in zip(stale, embeddings):
        chunk.embedding       = vec
        chunk.embedding_model = "bge-base-en-v1.5"
        chunk.index_status    = "indexed"
        chunk.content_hash    = compute_hash(chunk.content)

    DocumentChunk.objects.bulk_update(
        stale,
        ["embedding", "embedding_model", "index_status", "content_hash", "updated_at"],
    )

5. Composing a Guardrail Pipeline
class GuardedRAGPipeline:
    def __init__(self, rag, llm):
        self.rag = rag
        self.llm = llm

    def run(self, query: str, user_id: str) -&gt; dict:
        # --- Input guardrails ---
        if len(query) &gt; 2000:
            return {"error": "Query too long"}
        if detect_injection(query):
            return {"error": "Potential prompt injection detected"}
        if is_harmful(query):
            return {"error": "Query violates usage policy"}
        query = anonymise_query(query)

        # --- RAG pipeline ---
        chunks = self.rag.retrieve(query, user_id=user_id)  # ACL-filtered
        # Sanitise retrieved content
        safe_chunks = [c for c in chunks if not detect_injection(c.text)]
        response = self.rag.generate(query, safe_chunks)

        # --- Output guardrails ---
        groundedness = check_groundedness(response, safe_chunks, self.llm)
        if groundedness == "no":
            return {"error": "Could not find a reliable answer in the knowledge base"}
        issues = check_brand_safety(response)
        if issues:
            return {"error": f"Response blocked: {issues}"}
        response = scrub_pii_from_response(response)

        return {"answer": response, "groundedness": groundedness}

7. LLM-as-Judge
Using a strong LLM (e.g., GPT-4o) to judge outputs is now standard because it scales better than human annotation and correlates well with human judgment.
Prompt pattern:
You are an expert evaluator. Given the question, retrieved context, and answer below,
rate the faithfulness of the answer on a scale of 1–5.

Question: {question}
Context: {context}
Answer: {answer}

Faithfulness score (1=completely unfaithful, 5=fully supported): 
Pitfalls: - Judge LLM can be biased toward longer or more confident-sounding answers - Self-consistency: same judge returns different scores on re-runs → average over 3 runs - Use a different model as judge than as generator to avoid self-preference bias

4. Embedding Cache
Caching query embeddings avoids calling the embedding API for repeated or near-identical queries.
Simple TTL-based embedding cache:
from functools import lru_cache
import hashlib

@lru_cache(maxsize=10_000)
def embed_query_cached(query: str) -&gt; list[float]:
    return embedding_api.embed(query)
For multi-process / distributed systems, use Redis:
def embed_with_redis_cache(query: str) -&gt; list[float]:
    key = f"embed:{hashlib.sha256(query.encode()).hexdigest()}"
    cached = redis.get(key)
    if cached:
        return json.loads(cached)
    vec = embedding_api.embed(query)
    redis.setex(key, 86400, json.dumps(vec))  # 24h TTL
    return vec
Cost impact: At $0.02 per million tokens, embedding queries is cheap but adds ~20 ms latency. For high-frequency queries, caching eliminates this latency entirely.

Re-ranking with full chunk metadata
In prod you need to preserve IDs and metadata through the re-ranking step:
def rerank_chunks(
    query:   str,
    chunks:  list[dict],   # dicts with at minimum {"id": ..., "content": ...}
    top_k:   int = 5,
) -&gt; list[dict]:
    reranker = get_reranker()

    pairs  = [(query, c["content"]) for c in chunks]
    scores = reranker.predict(pairs, batch_size=32)

    ranked = sorted(
        zip(chunks, scores),
        key=lambda x: x[1],
        reverse=True,
    )

    return [
        {**chunk, "rerank_score": float(score)}
        for chunk, score in ranked[:top_k]
    ]

3. Implementation Pattern
from openai import OpenAI
from enum import Enum

client = OpenAI()

class QueryType(str, Enum):
    REFUND = "refund"
    TECHNICAL = "technical"
    GENERAL = "general"


def classify_query(query: str) -&gt; QueryType:
    """Use a fast model to classify the incoming query."""
    response = client.chat.completions.create(
        model="gpt-4o-mini",  # cheap + fast for classification
        messages=[
            {
                "role": "system",
                "content": (
                    "Classify the customer query into exactly one category: "
                    "'refund', 'technical', or 'general'. Respond with only the category name."
                ),
            },
            {"role": "user", "content": query},
        ],
    )
    raw = response.choices[0].message.content.strip().lower()
    return QueryType(raw)


SYSTEM_PROMPTS = {
    QueryType.REFUND: (
        "You are a billing specialist. Help the customer with their refund request. "
        "Be empathetic, explain the refund policy clearly, and collect any required information."
    ),
    QueryType.TECHNICAL: (
        "You are a senior technical support engineer. Diagnose the issue step by step. "
        "Ask clarifying questions and provide actionable solutions."
    ),
    QueryType.GENERAL: (
        "You are a helpful customer service agent. Answer general questions concisely "
        "and direct the customer to the right resource if needed."
    ),
}


def route_and_respond(query: str) -&gt; str:
    """Classify the query and route to the appropriate specialised handler."""
    query_type = classify_query(query)
    system_prompt = SYSTEM_PROMPTS[query_type]

    response = client.chat.completions.create(
        model="gpt-4o",
        messages=[
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": query},
        ],
    )
    return response.choices[0].message.content


# Usage
answer = route_and_respond("I was charged twice for my subscription last month.")

